class Solution:
    def strongPasswordChecker(self, password: str) -> int:
        n = len(password)
        missing_lower = missing_upper = missing_digit = 1
        for ch in password:
            if ch.islower():
                missing_lower = 0
            elif ch.isupper():
                missing_upper = 0
            elif ch.isdigit():
                missing_digit = 0
        missing_types = missing_lower + missing_upper + missing_digit

        replace = 0
        one_seq = two_seq = 0
        i = 2
        while i < n:
            if password[i] == password[i-1] == password[i-2]:
                length = 2
                while i < n and password[i] == password[i-1]:
                    length += 1
                    i += 1
                replace += length // 3
                if length % 3 == 0:
                    one_seq += 1
                elif length % 3 == 1:
                    two_seq += 1
            else:
                i += 1

        if n < 6:
            return max(6 - n, missing_types)
        elif n <= 20:
            return max(replace, missing_types)
        else:
            delete = n - 20
            replace -= min(delete, one_seq * 1) // 1
            replace -= min(max(delete - one_seq, 0), two_seq * 2) // 2
            replace -= max(delete - one_seq - 2 * two_seq, 0) // 3
            return delete + max(replace, missing_types)
